        meta = dict(payload.get("meta", {}))
        meta["output_type"] = "secondary_progression"
        meta["mode"] = "chart"
        meta["chart_type"] = "secondary_progression"
        meta["source_timestamp_utc"] = frame_a_timestamp_utc
        meta["target_timestamp_utc"] = target_timestamp_utc
