            timestamp_utc=dt_utc or "",
            location=location or {},
            settings=_resolve_settings(parsed),
        )
    except Exception as exc:
        raise RuntimeError(f"natal_compute_failed: {exc}") from exc
    return payload, dt_utc, location, []


