def _sign_and_degree(lon: float) -> tuple[str, float]:
    signs = [
        "Aries",
        "Taurus",
        "Gemini",
        "Cancer",
        "Leo",
        "Virgo",
        "Libra",
        "Scorpio",
        "Sagittarius",
        "Capricorn",
        "Aquarius",
        "Pisces",
    ]
    normalized = _normalize_deg(lon)
    return signs[int(normalized // 30)], normalized % 30.0


def _shift_angle_payload(payload: dict[str, Any], arc: float) -> dict[str, Any]:
