def _load_country_map(path: Path) -> dict[str, str]:
    if path in _COUNTRY_CACHE:
        return _COUNTRY_CACHE[path]
    if not path.exists():
        raise RuntimeError(f"countries_not_found:{path}")
    mapping: dict[str, str] = {}
    with path.open("r", encoding="utf-8") as handle:
        for line in handle:
            raw = line.strip()
            if not raw or raw.startswith("#"):
                continue
            parts = raw.split("\t")
            if len(parts) < 5:
                continue
            code = parts[0]
            name = parts[4]
            if code and name:
                mapping[code] = name
    _COUNTRY_CACHE[path] = mapping
    return mapping


def calc_astrocartography(
    frame_chart: dict,
    house_system: str,
    top_n: int = 50,
    cities_path: Path | None = None,
) -> dict:
    _ensure_ephe_path()

    dt_utc = _parse_timestamp(frame_chart["meta"]["timestamp_utc"])
    jd = _to_julday(dt_utc)

    path = cities_path
    if path is None:
        env_path = os.getenv("STYX_CITIES_PATH")
        if env_path:
            path = Path(env_path)
        else:
            path = Path(__file__).resolve().parents[2] / "data" / "cities5000.txt"

    country_path = os.getenv("STYX_COUNTRIES_PATH")
    if country_path:
        country_path = Path(country_path)
    else:
        country_path = Path(__file__).resolve().parents[2] / "data" / "countryInfo.txt"

    cities = _load_cities(path)
    try:
        country_map = _load_country_map(Path(country_path))
    except RuntimeError:
        country_map = {}

    body_lons = {}
    for name in PLANET_ORDER:
        if name in frame_chart["bodies"]:
            body_lons[name] = float(frame_chart["bodies"][name]["lon"])

    points = frame_chart.get("points", {})
    crossing_lons = dict(body_lons)
    if "nn" in points:
        crossing_lons["nn"] = float(points["nn"]["lon"])
    if "sn" in points:
        crossing_lons["sn"] = float(points["sn"]["lon"])

    max_orb = float(os.getenv("STYX_ASTRO_MAX_ORB", "2.0"))
    cross_top_n = int(os.getenv("STYX_ASTRO_CROSS_TOP_N", "50"))

    results: List[dict] = []
    crossings: List[dict] = []
    for city in cities:
        try:
            angles = _calc_angles_for_location(jd, city["lat"], city["lon"], house_system)
        except RuntimeError:
            continue

        line_hits: List[dict] = []
        for body_name, body_lon in crossing_lons.items():
            for angle_name, angle_lon in angles.items():
                orb = _angular_distance(body_lon, angle_lon)
                if orb <= max_orb:
                    line_hits.append(
                        {
                            "body": body_name,
                            "angle_line": angle_name,
                            "orb": orb,
                        }
                    )

        for body_name, body_lon in body_lons.items():
            for angle_name, angle_lon in angles.items():
                orb = _angular_distance(body_lon, angle_lon)
                if orb > max_orb:
                    continue
                country_name = country_map.get(city["country"], city["country"])
                results.append(
                    {
                        "body": body_name,
                        "angle_line": angle_name,
                        "city": city["city"],
                        "country": country_name,
                        "lat": city["lat"],
                        "lon": city["lon"],
                        "orb": orb,
                        "population": city["population"],
                    }
                )

        if len(line_hits) > 1:
            for i in range(len(line_hits)):
                for j in range(i + 1, len(line_hits)):
                    a = line_hits[i]
                    b = line_hits[j]
                    if a["body"] == b["body"] and a["angle_line"] == b["angle_line"]:
                        continue
                    country_name = country_map.get(city["country"], city["country"])
                    crossings.append(
                        {
                            "a_body": a["body"],
                            "a_line": a["angle_line"],
                            "a_orb": a["orb"],
                            "b_body": b["body"],
                            "b_line": b["angle_line"],
                            "b_orb": b["orb"],
                            "city": city["city"],
                            "country": country_name,
                            "lat": city["lat"],
                            "lon": city["lon"],
                            "population": city["population"],
                        }
                    )

    results.sort(key=lambda item: (item["orb"], -item["population"], item["city"]))
    trimmed = results[: max(top_n, 0)]
    for item in trimmed:
        item.pop("population", None)
    crossings.sort(key=lambda item: (max(item["a_orb"], item["b_orb"]), -item["population"], item["city"]))
    cross_trimmed = crossings[: max(cross_top_n, 0)]
    for item in cross_trimmed:
        item.pop("population", None)
    return {"results": trimmed, "crossings": cross_trimmed}


def calc_chart(
    chart_type: str,
    timestamp_utc: str,
    location: dict,
    settings,
    round_output: bool = True,
) -> dict:
    warnings: List[str] = []

    _ensure_ephe_path()

    dt_utc = _parse_timestamp(timestamp_utc)
    jd = swe.julday(
        dt_utc.year,
        dt_utc.month,
        dt_utc.day,
        dt_utc.hour + dt_utc.minute / 60 + dt_utc.second / 3600 + dt_utc.microsecond / 3_600_000_000,
    )

    cusps, asc, mc, armc, hsys = _calc_houses(jd, location["lat"], location["lon"], settings.house_system)
    dsc = _normalize_deg(asc + 180.0)
    ic = _normalize_deg(mc + 180.0)

    eps = _calc_obliquity(jd)

    bodies: Dict[str, dict] = {}
    for name in PLANET_ORDER:
        body = _calc_body(jd, BODY_IDS[name], name)
        body["house"] = _assign_house(body["lon"], body["lat"], cusps, armc, location["lat"], hsys, eps)
        bodies[name] = body

    asteroids: Dict[str, dict] = {}
    for name in ASTEROID_ORDER:
        try:
            body = _calc_body(jd, ASTEROID_IDS[name], name)
        except RuntimeError as exc:
            if name == "lilith (asteroid)":
                warnings.append(str(exc))
                body = _stub_body()
            else:
                raise
        body["house"] = _assign_house(body["lon"], body["lat"], cusps, armc, location["lat"], hsys, eps)
        asteroids[name] = body

    nn = _calc_body(jd, getattr(swe, "TRUE_NODE", 0), "true_node")
    nn["house"] = _assign_house(nn["lon"], nn["lat"], cusps, armc, location["lat"], hsys, eps)

    sn_lon = _normalize_deg(nn["lon"] + 180.0)
    sn_lat = -nn["lat"]
    sn_house = _assign_house(sn_lon, sn_lat, cusps, armc, location["lat"], hsys, eps)
    sn = _body_like_from_lon_lat(sn_lon, sn_lat, nn["speed"], sn_house)

    sun_lon = bodies["sun"]["lon"]
    moon_lon = bodies["moon"]["lon"]
    saturn_lon = bodies["saturn"]["lon"]
    venus_lon = bodies["venus"]["lon"]
    mars_lon = bodies["mars"]["lon"]
    jupiter_lon = bodies["jupiter"]["lon"]
    is_day = bodies["sun"]["house"] >= 7

    lots_raw = _calc_lots(is_day, asc, sun_lon, moon_lon, saturn_lon, venus_lon, mars_lon, jupiter_lon)
    lots = {}
    for name, payload in lots_raw.items():
        lot_lon = payload["lon"]
        lot_house = _assign_house(lot_lon, 0.0, cusps, armc, location["lat"], hsys, eps)
        lots[name] = _body_like_from_lon_lat(lot_lon, 0.0, 0.0, lot_house)

    lilith = _calc_body(jd, swe.MEAN_APOG, "lilith_mean")
    lilith["house"] = _assign_house(lilith["lon"], lilith["lat"], cusps, armc, location["lat"], hsys, eps)

    angles = {
        "asc": _angle_payload(asc),
        "dsc": _angle_payload(dsc),
        "mc": _angle_payload(mc),
        "ic": _angle_payload(ic),
    }

    cusps_out = {str(i): _angle_payload(cusps[str(i)]) for i in range(1, 13)}

    if transit_type == "transit":
        prefix_a = "natal_"
        prefix_b = "tr_"
    else:
        prefix_a = f"{label_a}_"
        prefix_b = f"{label_b}_"

    aspect_set, aspect_angles, aspect_orbs, aspect_classes = _default_aspect_config()
    targets_a = _build_aspect_targets(frame_a_chart)
    targets_b = _build_aspect_targets(frame_b_chart)
    aspects = _calc_cross_aspects(
        targets_a,
        targets_b,
        aspect_angles,
        aspect_orbs,
        aspect_classes,
        prefix_a,
        prefix_b,
    )

    meta = {
        "transit_type": transit_type,
        "timestamp_utc": frame_b_chart["meta"]["timestamp_utc"],
    }

    payload = {
        "meta": meta,
        "aspects": aspects,
    }

    payload = round_payload(payload, 2)
    return _wrap(payload, frame_b_chart["meta"]["timestamp_utc"], frame_b_chart["meta"]["location"], frame_b_req.settings)


@app.post("/v1/timeline")
def timeline(req: TimelineRequest, request: Request) -> dict:
    settings = req.settings or req.frame_a.settings or Settings()
    natal_location = _resolve_location(req.frame_a.metadata.location, request)
    natal_timestamp = _resolve_timestamp(req.frame_a.metadata.timestamp_utc)
    input_summary = _build_input_summary(natal_timestamp, natal_location)

    timeline_type = req.metadata.timeline_type or "transit"
    raw_bodies = req.metadata.bodies or []
    bodies_input = [str(item).strip().lower() for item in raw_bodies if str(item).strip()]

    try:
        natal_chart = calc_chart(
            chart_type="natal",
            timestamp_utc=natal_timestamp,
            location=natal_location,
            settings=settings,
            round_output=False,
        )
    except RuntimeError as exc:
        raise HTTPException(status_code=500, detail=str(exc)) from exc

    if timeline_type == "secondary_progression":
        payload = build_progression_timeline(
            natal_chart=natal_chart,
            start_utc=req.metadata.start_utc,
            end_utc=req.metadata.end_utc,
        )
        payload_meta = dict(payload.get("meta", {}))
        payload_meta["timeline_type"] = "secondary_progression"
        payload["meta"] = payload_meta
        return envelope_response(
            request=request,
            data=payload,
            settings=_build_envelope_settings(settings),
            input_summary=input_summary,
        )

    if not bodies_input:
        raise HTTPException(status_code=422, detail="bodies is required for timeline_type=transit/solar_arc")

    lunation_keys = {"lunations", "eclipses", "new_moon", "full_moon", "solar_eclipse", "lunar_eclipse"}
    if timeline_type == "transit" and lunation_keys.intersection(bodies_input):
        lunation_type = None
        if "lunations" not in bodies_input:
            types: list[str] = []
            if "eclipses" in bodies_input:
                types.extend(["solar_eclipse", "lunar_eclipse"])
            for key in ("new_moon", "full_moon", "solar_eclipse", "lunar_eclipse"):
                if key in bodies_input and key not in types:
                    types.append(key)
            lunation_type = " | ".join(types) if types else None
        events = filter_lunations(
            start_utc=req.metadata.start_utc,
            end_utc=req.metadata.end_utc,
            lunation_type=lunation_type,
        )
        return envelope_response(
            request=request,
            data={
                "meta": {
                    "start_utc": req.metadata.start_utc,
                    "end_utc": req.metadata.end_utc,
                    "timeline_type": "transit",
                    "bodies": bodies_input,
                },
                "events": events,
            },
            settings=_build_envelope_settings(settings),
            input_summary=input_summary,
        )

    bodies: list[str] = []
    for body in bodies_input:
        if body == "nodes":
            bodies.extend(["nn", "sn"])
        elif body in {"nn", "sn", "jupiter", "saturn", "uranus", "neptune", "pluto"}:
            bodies.append(body)
        else:
            raise HTTPException(status_code=422, detail=f"Unsupported timeline body: {body}")
    bodies = list(dict.fromkeys(bodies))

    if timeline_type == "solar_arc":
        payload = build_solar_arc_timeline(
            natal_chart=natal_chart,
            start_utc=req.metadata.start_utc,
